"use client";

import { useSearchParams } from "next/navigation";
import { getTopicsList } from "@/data/topics";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Terminal } from "lucide-react";
import { use } from "react";

export default function LearnPage({ params }: { params: Promise<{ language: string }> }) {
    const resolvedParams = use(params);
    const searchParams = useSearchParams();
    const topicId = searchParams.get("topic") || "flowcharts"; // default topic
    const topics = getTopicsList();

    const currentTopic = topics.find((t) => t.id === topicId) || topics[0];
    const language = resolvedParams.language === "cpp" ? "C++" : "C";

    return (
        <div className="max-w-4xl mx-auto p-6 md:p-10 space-y-8">
            <div>
                <h1 className="text-4xl font-extrabold tracking-tight mb-2 flex items-center gap-3">
                    {currentTopic.title}
                    <span className="text-sm font-normal px-3 py-1 bg-primary/10 text-primary rounded-full ring-1 ring-primary/20">
                        {language}
                    </span>
                </h1>
                <p className="text-xl text-muted-foreground">
                    {currentTopic.tldr}
                </p>
            </div>

            <div className="prose prose-neutral dark:prose-invert max-w-none">
                {/* We use dangerouslySetInnerHTML safely here since our JSON content has basic safe HTML <br> tags */}
                <div
                    className="text-lg leading-relaxed text-foreground/90 bg-muted/20 p-6 rounded-2xl border"
                    dangerouslySetInnerHTML={{ __html: currentTopic.explanation }}
                />
            </div>

            {currentTopic.syntax && (
                <Card className="border-border">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Terminal className="w-5 h-5" />
                            Syntax
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <pre className="p-4 rounded-xl bg-card border overflow-x-auto text-sm">
                            <code>{resolvedParams.language === "cpp" ? currentTopic.syntax.cpp : currentTopic.syntax.c}</code>
                        </pre>
                    </CardContent>
                </Card>
            )}

            {currentTopic.example && (
                <Card className="border-border">
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Terminal className="w-5 h-5 text-green-500" />
                            Example Code
                        </CardTitle>
                    </CardHeader>
                    <CardContent>
                        <pre className="p-4 rounded-xl bg-card border overflow-x-auto text-sm">
                            <code>{resolvedParams.language === "cpp" ? currentTopic.example.cpp : currentTopic.example.c}</code>
                        </pre>
                    </CardContent>
                </Card>
            )}
        </div>
    );
}

"use client";

import { Workspace } from "@/components/editor/Workspace";
import { notFound } from "next/navigation";
import { use } from "react";

const problemData: Record<string, { title: string, lang: "c" | "cpp", desc: React.ReactNode, template: string }> = {
    "hello-world": {
        title: "1. Hello World",
        lang: "c",
        desc: (
            <>
                <p>Write a program that prints exactly <code>Hello World!</code> to the standard output.</p>
                <p className="mt-4 text-sm text-muted-foreground">Hint: Use the <code>printf()</code> function.</p>
            </>
        ),
        template: '#include <stdio.h>\n\nint main() {\n    // Write your code here\n    \n    return 0;\n}'
    },
    "reverse-string": {
        title: "2. Reverse String",
        lang: "cpp",
        desc: (
            <>
                <p>Write a function that reverses a string. The input string is given as an array of characters.</p>
                <p>You must do this by modifying the input array in-place.</p>
                <h4>Example:</h4>
                <pre className="bg-muted p-2 rounded-md font-mono text-sm mt-2">
                    Input: s = ["h","e","l","l","o"]<br />
                    Output: ["o","l","l","e","h"]
                </pre>
            </>
        ),
        template: '#include <iostream>\n#include <vector>\n#include <string>\n\nusing namespace std;\n\nvoid reverseString(vector<char>& s) {\n    // Write your code here\n    \n}\n\nint main() {\n    vector<char> str = {\'h\', \'e\', \'l\', \'l\', \'o\'};\n    reverseString(str);\n    for(char c : str) cout << c;\n    return 0;\n}'
    }
};

export default function ProblemPage({ params }: { params: Promise<{ id: string }> }) {
    const resolvedParams = use(params);
    const prob = problemData[resolvedParams.id];

    if (!prob) {
        return notFound();
    }

    return (
        <div className="w-full h-[calc(100vh-3.5rem)]">
            <Workspace
                problemTitle={prob.title}
                problemDescription={prob.desc}
                language={prob.lang}
                initialCode={prob.template}
            />
        </div>
    );
}

"use client";

import { useState } from "react";
import { CodeEditor } from "./CodeEditor";
import { executeCode } from "@/lib/piston";
import { Play, Loader2, CheckCircle2, XCircle } from "lucide-react";
import { Button } from "@/components/ui/button";
import { ResizableHandle, ResizablePanel, ResizablePanelGroup } from "@/components/ui/resizable";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { toast } from "sonner";
import { useProgress } from "@/lib/progress";

interface WorkspaceProps {
    initialCode?: string;
    language?: "c" | "cpp";
    problemTitle: string;
    problemDescription: React.ReactNode;
}

export function Workspace({
    initialCode = '#include <stdio.h>\n\nint main() {\n    printf("Hello World!\\n");\n    return 0;\n}',
    language = "c",
    problemTitle,
    problemDescription,
}: WorkspaceProps) {
    const [code, setCode] = useState(initialCode);
    const [isRunning, setIsRunning] = useState(false);
    const [output, setOutput] = useState("");
    const [error, setError] = useState("");

    const { markProblemCompleted } = useProgress();

    const handleRunCode = async () => {
        setIsRunning(true);
        setOutput("");
        setError("");

        try {
            const result = await executeCode(language, code);
            if (result.compile_output) {
                setError(result.compile_output);
                toast.error("Compilation Error");
            } else if (result.stderr) {
                setError(result.stderr);
                toast.error("Execution Error");
            } else {
                setOutput(result.stdout);
                toast.success("Executed successfully");
                if (result.code === 0 && !result.stderr && result.stdout) {
                    // Basic validation. In a real scenario we compare multiple test cases.
                    // For now, if code runs without error, mark as completed
                    markProblemCompleted("hello-world"); // Using a generic or pass problemId
                }
            }
        } catch (err) {
            setError("Failed to reach execution service.");
            toast.error("Service unavailable");
        } finally {
            setIsRunning(false);
        }
    };

    return (
        <>
            {/* @ts-expect-error type missing */}
            <ResizablePanelGroup direction="horizontal" className="h-[calc(100vh-3.5rem)] rounded-none border-t">
                <ResizablePanel defaultSize={40} minSize={30} className="bg-background">
                    <ScrollArea className="h-full">
                        <div className="p-6">
                            <h2 className="text-2xl font-bold mb-4">{problemTitle}</h2>
                            <div className="prose prose-neutral dark:prose-invert max-w-none">
                                {problemDescription}
                            </div>
                        </div>
                    </ScrollArea>
                </ResizablePanel>

                <ResizableHandle withHandle />

                <ResizablePanel defaultSize={60} minSize={30}>
                    {/* @ts-expect-error type missing */}
                    <ResizablePanelGroup direction="vertical">
                        <ResizablePanel defaultSize={70} className="relative bg-zinc-950">
                            <div className="absolute top-2 right-4 z-10 flex gap-2">
                                <Button
                                    size="sm"
                                    className="bg-green-600 hover:bg-green-700 text-white"
                                    onClick={handleRunCode}
                                    disabled={isRunning}
                                >
                                    {isRunning ? (
                                        <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                    ) : (
                                        <Play className="mr-2 h-4 w-4" />
                                    )}
                                    Run Code
                                </Button>
                            </div>
                            <CodeEditor language={language} code={code} onChange={(v) => setCode(v || "")} />
                        </ResizablePanel>

                        <ResizableHandle withHandle />

                        <ResizablePanel defaultSize={30} className="bg-muted/30 p-0">
                            <Tabs defaultValue="output" className="h-full flex flex-col">
                                <div className="px-4 pt-2 border-b">
                                    <TabsList className="bg-transparent">
                                        <TabsTrigger value="output" className="data-[state=active]:bg-background">Terminal</TabsTrigger>
                                        <TabsTrigger value="testcases" className="data-[state=active]:bg-background">Test Cases</TabsTrigger>
                                    </TabsList>
                                </div>
                                <ScrollArea className="flex-1 p-4 font-mono text-sm">
                                    <TabsContent value="output" className="mt-0 h-full">
                                        {isRunning ? (
                                            <div className="text-muted-foreground flex items-center gap-2">
                                                <Loader2 className="h-4 w-4 animate-spin" /> Executing...
                                            </div>
                                        ) : error ? (
                                            <div className="text-red-400 whitespace-pre-wrap">{error}</div>
                                        ) : output ? (
                                            <div className="text-green-400 whitespace-pre-wrap">{output}</div>
                                        ) : (
                                            <div className="text-muted-foreground">Run code to see output here.</div>
                                        )}
                                    </TabsContent>
                                    <TabsContent value="testcases" className="mt-0">
                                        <div className="text-muted-foreground italic">Custom test cases will appear here.</div>
                                    </TabsContent>
                                </ScrollArea>
                            </Tabs>
                        </ResizablePanel>
                    </ResizablePanelGroup>
                </ResizablePanel>
            </ResizablePanelGroup>
        </>
    );
}

import axios from "axios";

const PISTON_API_URL = "https://emkc.org/api/v2/piston";

export interface ExecutionResult {
    stdout: string;
    stderr: string;
    compile_output?: string;
    code: number;
}

export const executeCode = async (
    language: "c" | "cpp",
    code: string,
    stdin: string = ""
): Promise<ExecutionResult> => {
    try {
        // Piston requires finding the right language version
        const versionMap = {
            c: "10.2.0",
            cpp: "10.2.0",
        };

        const response = await axios.post(`${PISTON_API_URL}/execute`, {
            language: language === "cpp" ? "c++" : "c",
            version: versionMap[language],
            files: [
                {
                    name: language === "cpp" ? "main.cpp" : "main.c",
                    content: code,
                },
            ],
            stdin: stdin,
        });

        const run = response.data.run;
        const compile = response.data.compile;

        return {
            stdout: run.stdout,
            stderr: run.stderr,
            compile_output: compile ? compile.stderr : undefined,
            code: run.code,
        };
    } catch (error: any) {
        console.error("Execution failed:", error);
        return {
            stdout: "",
            stderr: error.message || "Failed to reach execution API",
            code: 1,
        };
    }
};

